### Chapter 4-6: 구현 상세

#### 4.1 BackPropagation의 효율적 구현

```rust
/// v30.1의 핵심: 효율적인 역전파

pub struct EfficientBackprop {
    /// Forward pass의 중간 계산값 저장
    pub activations: Vec<Vec<f32>>,

    /// Gradient 캐시
    pub gradient_cache: HashMap<u64, Vec<f32>>,

    /// GPU 메모리 효율성
    pub memory_efficient_mode: bool,
}

impl EfficientBackprop {
    /// Forward Pass: O(n)
    pub fn forward(&mut self, input: &[f32]) -> Vec<f32> {
        let mut activation = input.to_vec();

        for (i, layer) in self.activations.iter_mut().enumerate() {
            // Cache activation for backward pass
            let prev = activation.clone();
            activation = self.compute_layer(&prev);
            *layer = activation.clone();
        }

        activation
    }

    /// Backward Pass: O(n), 메모리 효율화
    pub fn backward(&mut self, gradient: &[f32]) {
        let mut grad = gradient.to_vec();

        // 역순으로 gradient 계산
        for i in (0..self.activations.len()).rev() {
            let layer_grad = self.compute_gradient(&self.activations[i], &grad);
            self.gradient_cache.insert(i as u64, layer_grad.clone());

            // 이전 레이어로 gradient 전파
            grad = self.backprop_to_previous(&grad);
        }
    }

    fn compute_layer(&self, input: &[f32]) -> Vec<f32> {
        input.iter().map(|x| x.max(0.0)).collect()  // ReLU
    }

    fn compute_gradient(&self, activation: &[f32], grad_output: &[f32]) -> Vec<f32> {
        activation.iter()
            .zip(grad_output.iter())
            .map(|(a, g)| if *a > 0.0 { *g } else { 0.0 })
            .collect()
    }

    fn backprop_to_previous(&self, grad: &[f32]) -> Vec<f32> {
        // 이전 레이어로 gradient 전파
        grad.iter().map(|g| g * 0.5).collect()  // Simplified
    }
}
```

