pub struct MachineController {
    pub id: u64,
    pub functions: Vec<CognitiveFunction>,
    pub local_model: LocalNeuralModel,
}

pub struct ClusterController {
    pub id: u64,
    pub machines: Vec<MachineController>,
    pub cluster_model: ClusterNeuralModel,
}

pub struct PlanetaryController {
    pub clusters: Vec<ClusterController>,
    pub global_model: GlobalNeuralModel,

    /// 행성 규모의 파라미터
