            cluster.cluster_model.update();
        }

        // Level 4: 행성 전체가 글로벌 모델 업데이트
        println!("\nLevel 4: 행성 규모 글로벌 모델 동기화");
        self.level_4_planetary.global_model.update();

        println!("\n  ✓ 계층적 학습 완료");
